const STEPS = [
  { icon: '🔍', title: 'Search Turf', desc: 'Find nearby turfs with filters for sport, price and availability.' },
  { icon: '📅', title: 'Select Slot', desc: 'Choose your preferred date and time from available slots.' },
  { icon: '💳', title: 'Book & Pay', desc: 'Complete payment securely and get instant booking confirmation.' },
  { icon: '⚽', title: 'Play & Enjoy', desc: 'Head to the venue and enjoy your game!' },
];

export default function HowItWorks() {
  return (
    <section style={{ padding: '4rem 2rem', background: '#f9f9f9', textAlign: 'center' }}>
      <h2 style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>How It Works</h2>
      <p style={{ color: '#666', marginBottom: '3rem' }}>
        Book your perfect turf in under 2 minutes
      </p>
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
        gap: '2rem',
        maxWidth: '900px',
        margin: '0 auto',
      }}>
        {STEPS.map((step, i) => (
          <div key={i} style={{
            background: 'white',
            borderRadius: '16px',
            padding: '2rem 1.5rem',
            boxShadow: '0 2px 12px rgba(0,0,0,0.07)',
          }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>{step.icon}</div>
            <div style={{
              background: '#1ebe74',
              color: 'white',
              borderRadius: '50%',
              width: '28px',
              height: '28px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '0.85rem',
              fontWeight: '700',
              margin: '0 auto 1rem',
            }}>
              {i + 1}
            </div>
            <h3 style={{ marginBottom: '0.5rem' }}>{step.title}</h3>
            <p style={{ color: '#666', fontSize: '0.9rem', lineHeight: 1.6 }}>{step.desc}</p>
          </div>
        ))}
      </div>
    </section>
  );
}
